// A grayscale photo slot: real base64 fashion photography (grayscale, object-fit
// cover) fills the neumorphic-framed `.ph`; it falls back to the portrait marker
// when no image is passed. Optional editorial caption + corner tag sit on top.
const photo = (cls: string, cap = '', tag = '', img = '') =>
  `<figure class="photo ${cls}${img ? ' has-img' : ''}"><div class="ph">${img ? `<img src="${img}" alt="" loading="lazy">` : FIGURE}</div>` +
  `${tag ? `<span class="tag">${tag}</span>` : ''}${cap ? `<figcaption>${cap}</figcaption>` : ''}</figure>`;

