// Tiny inline script (the sandbox allows scripts): single-select the color + size
// groups, and mirror the chosen color into the swatch dot + label. Pure DOM/style
// mutation, no same-origin needed.
const SHOP_SCRIPT = `<script>(function(){
  function single(sel,labelId){
    var lbl=labelId?document.getElementById(labelId):null,dot=document.getElementById('cdot');
    document.querySelectorAll(sel).forEach(function(b){b.addEventListener('click',function(){
      document.querySelectorAll(sel).forEach(function(x){x.classList.remove('on');x.setAttribute('aria-pressed','false');});
      b.classList.add('on');b.setAttribute('aria-pressed','true');
      if(lbl&&b.dataset.name)lbl.textContent=b.dataset.name;
      if(dot&&sel==='.swatch'&&b.dataset.color)dot.style.background=b.dataset.color;
    });});
  }
  single('.swatch','cname');single('.size',null);
})();</script>`;

const footer = () => `<footer><div class="wrap"><div class="foot">
  <a class="wordmark" href="#">Vesper</a>
  <div class="fnote">Studio Vesper, Autumn / Winter 2026. Looks staged for preview.</div>
</div></div></footer>`;

// v1 — core editorial landing: the split hero + the category index marquee.
const V1 = page(nav() + hero() + footer());

// v2 — added The Collection lookbook (a campaign feature + a three-up look grid).
const V2 = page(nav() + hero() + lookbook() + footer());

// v3 — latest: an interactive featured-piece configurator (color swatches + size
// pills), with the inline selection script at the end of the body.
const V3 = page(nav() + hero() + lookbook() + featured() + footer() + SHOP_SCRIPT);

const dataUrl = (html: string) => `data:text/html;charset=utf-8,${encodeURIComponent(html)}`;
// Version id → framed preview URL. Restoring a generation points the artifact at
// the matching URL via its imperative navigate().
const VURL: Record<string, string> = { v1: dataUrl(V1), v2: dataUrl(V2), v3: dataUrl(V3) };
const LATEST_URL = VURL.v3;

