const FEATURED_TSX = `import { useState } from 'react';

const colors = [
  { name: 'Charcoal', hex: '#3b3f47' },
  { name: 'Camel', hex: '#b9966a' },
  { name: 'Ivory', hex: '#ece7dc' },
  { name: 'Black', hex: '#1a1c20' },
];
const sizes = ['XS', 'S', 'M', 'L', 'XL'];

export function Featured() {
  const [color, setColor] = useState(colors[0]);
  const [size, setSize] = useState('M');
  return (
    <section id="shop" className="featured">
      <figure className="photo"><img src="/looks/coat.jpg" alt="The Wool Coat" /></figure>
      <div className="detail">
        <h3 className="serif">The Wool Coat</h3>
        <p className="pr serif">$680</p>
        <p className="opt">Color <b>{color.name}</b></p>
        <div className="swatches">
          {colors.map((c) => (
            <button key={c.name} aria-pressed={c.name === color.name}
              style={{ background: c.hex }} onClick={() => setColor(c)} />
          ))}
        </div>
        <div className="sizes">
          {sizes.map((s) => (
            <button key={s} aria-pressed={s === size} onClick={() => setSize(s)}>{s}</button>
          ))}
        </div>
        <button className="btn-primary">Add to bag</button>
      </div>
    </section>
  );
}`;
const GLOBALS_CSS = `:root {
  --bg: #e9ebf0;
  --ink: #1a1d23;
  /* Editorial display face. Swap to a base64 @font-face Playfair / Bodoni later. */
  --display-font: 'Playfair Display', Georgia, 'Times New Roman', serif;
  --raise: 9px 9px 22px #c7cbd4, -9px -9px 22px #ffffff;
  --inset: inset 5px 5px 11px #c7cbd4, inset -5px -5px 11px #ffffff;
}
body { background: var(--bg); color: var(--ink); }
.serif { font-family: var(--display-font); }
.photo { border-radius: 18px; box-shadow: var(--raise); }
.btn-primary { background: #23262e; color: #f6f7f9; border-radius: 999px; }
.swatch.on, .size.on { box-shadow: var(--inset); }`;

const FILES = [
  { path: 'app/page.tsx', language: 'tsx', type: 'other' as const, code: PAGE_TSX, url: LATEST_URL },
  { path: 'app/globals.css', language: 'css', type: 'other' as const, code: GLOBALS_CSS, url: LATEST_URL },
  { path: 'components/hero.tsx', language: 'tsx', type: 'other' as const, code: HERO_TSX, url: LATEST_URL },
  { path: 'components/lookbook.tsx', language: 'tsx', type: 'other' as const, code: LOOKBOOK_TSX, url: LATEST_URL },
  { path: 'components/featured.tsx', language: 'tsx', type: 'other' as const, code: FEATURED_TSX, url: LATEST_URL },
  { path: 'package.json', language: 'json', type: 'other' as const, code: '{\n  "name": "vesper",\n  "dependencies": { "next": "15.0.0", "react": "19.0.0" }\n}', url: LATEST_URL },
];

// ── The chat thread: each assistant turn is a generation tied to a version ──
const THREAD: { role: 'user' | 'assistant'; md: string; version?: string }[] = [
  { role: 'user', md: 'Build an editorial landing page for Vesper, a fashion label. Go for a high-fashion look with a serif wordmark, a big model photo in the hero, and a clean soft-UI frame.' },
  { role: 'assistant', md: 'Built the Vesper landing: an editorial split hero with a serif display headline beside a large grayscale model shot, framed in soft raised shadow over a clean white surface. A category index runs beneath. The photography sits in soft grayscale to match the editorial mood.', version: 'v1' },
  { role: 'user', md: 'Add a lookbook section with the collection.' },
  { role: 'assistant', md: 'Added **The Collection** - a lookbook with a campaign feature shot and a three-up grid of soft-framed portrait cards. The Code tab now has `components/lookbook.tsx`.', version: 'v2' },
  { role: 'user', md: 'Add a featured piece people can configure by color and size.' },
  { role: 'assistant', md: 'Added a **featured piece** spotlight with a large photo and an interactive color and size selector - tap a swatch or a size and the choice updates. This is the current preview.', version: 'v3' },
];

export const V0: Story = {
  name: 'v0',
  render: () => {
    // The artifact element — captured in its ref so Restore can drive its
    // imperative navigate(). The active version is whichever URL is framed.
    let art: El | undefined;
    const [activeVersion, setActiveVersion] = createSignal('v3');
    const restore = (id: string) => {
      setActiveVersion(id);
      // REAL kai-artifact API: push + load the version's URL in the preview. The
      // "version" framing is ours; the kit has only this URL history primitive.
      (art?.navigate as ((url: string) => void) | undefined)?.(VURL[id]);
    };

    return (
      <div class="h-screen w-full">
        {/* The split shell: chat (left) | preview (right). Composed from
            kai-resizable + the chat + kai-artifact. */}
        <kai-resizable orientation="horizontal" class="block h-full">
          {/* LEFT — chat thread + composer. A width floor (min) keeps it from
              going skinny; a ceiling (max) keeps it from eating the preview. The
              `size` attribute is BOTH the initial size and the dblclick-reset
              default (kai-resizable stashes it as the default). */}
          <kai-resizable-item size="40%" min="360px" max="480px">
            <div class="flex h-full flex-col bg-background">
              {/* chat header: title + Share (real) */}
              <header class="flex shrink-0 items-center justify-between gap-3 border-b border-border px-4 py-2.5">
                <div class="flex items-center gap-2">
                  <span class="text-sm font-medium">Vesper editorial</span>
                  <kai-badge variant="outline">Generating UI</kai-badge>
                </div>
                <kai-tooltip content="Share this build">
                  <kai-button variant="ghost" size="sm" icon="share">Share</kai-button>
                </kai-tooltip>
              </header>

              {/* thread (scrolls) */}
              <div class="min-h-0 flex-1 overflow-y-auto">
                <div class="mx-auto flex max-w-2xl flex-col gap-4 px-4 py-5">
                  <For each={THREAD}>
                    {(turn) => (
                      <div class="flex flex-col gap-2">
                        <kai-message
                          ref={(el) => { const m = el as El; m.role = turn.role; m.content = turn.md; m.avatar = 'none'; }}
                          style={{ display: 'block' }}
                        ></kai-message>
                        {/* A generation → a version chip + Restore. The chip marks
                            the version currently framed; Restore navigates the real
                            artifact to an earlier generation. */}
                        <Show when={turn.version}>
                          <div class="flex items-center gap-2 pl-1">
                            <kai-badge variant={turn.version === activeVersion() ? undefined : 'outline'}>
                              {turn.version}{turn.version === activeVersion() ? ' · showing' : ''}
                            </kai-badge>
                            <Show when={turn.version !== activeVersion()}>
                              <kai-button
                                ref={(el) => { el.addEventListener('kai-click', () => restore(turn.version!)); }}
                                variant="ghost"
                                size="sm"
                              >
                                <RotateCcw slot="icon" class="size-3.5" />
                                Restore this version
                              </kai-button>
                            </Show>
                          </div>
                        </Show>
                      </div>
                    )}
                  </For>
                </div>
              </div>

              {/* composer: + (attach / Figma) · model · mode */}
              <div class="shrink-0 border-t border-border p-3">
                <div class="mx-auto max-w-2xl">
                  <kai-prompt-input
                    ref={(el) => { (el as El).attach = false; }}
                    placeholder="Describe a change, or attach a screenshot..."
                  >
                    <div slot="toolbar-start" class="flex items-center gap-1.5">
                      <kai-menu
                        ref={(el) => { (el as El).items = [
                          { id: 'image', label: 'Attach image', icon: 'paperclip' },
                          { id: 'figma', label: 'Import from Figma' },
                          { id: 'url', label: 'Import from a URL', icon: 'globe' },
                        ]; }}
                        trigger-icon="plus"
                        label="Add"
                      ></kai-menu>
                      <kai-model-switcher
                        ref={(el) => { const m = el as El; m.models = [
                          { id: 'v0-md', name: 'v0-1.5-md' },
                          { id: 'v0-lg', name: 'v0-1.5-lg' },
                        ]; m.currentModel = 'v0-lg'; }}
                      ></kai-model-switcher>
                      <kai-menu
                        ref={(el) => { (el as El).items = [
                          { heading: true, label: 'Mode' },
                          { id: 'design', label: 'Design', checked: true },
                          { id: 'chat', label: 'Chat' },
                        ]; }}
                        trigger-label="Design"
                        trigger-icon-trailing="chevron-down"
                      ></kai-menu>
                    </div>
                  </kai-prompt-input>
                </div>
              </div>
            </div>
          </kai-resizable-item>

          {/* RIGHT — the preview pane: the REAL <kai-artifact> with its own chrome
              (Preview/Code, refresh, expand, open-in-tab, address bar). */}
          <kai-resizable-item>
            <div class="flex h-full flex-col bg-surface">
              {/* The artifact fills the pane. REAL toolbar controls (rendered by
                  the element itself): refresh, expand-to-fill (maximizes this pane
                  via the kai-resizable maximize protocol), open-in-new-tab, the
                  Preview|Code toggle, and the ADDRESS BAR. Back/forward/home are
                  hidden via the no-* flags. The framed preview is a `data:` blob, so
                  `displayUrl` shows a clean, read-only address (`/index.html`)
                  in the bar instead of leaking the blob. Everything but `expandable`/
                  `style` is set as a property in the ref: `src` (the framed preview),
                  `files` (the Code tab tree + source), `defaultTab`, `iframeTitle`,
                  `displayUrl`, and the no-* visibility flags. Solid runs the ref
                  BEFORE the element connects, so these are present at first mount. */}
              <div class="min-h-0 flex-1">
                <kai-artifact
                  ref={(el) => {
                    const a = el as El;
                    a.files = FILES;
                    a.src = LATEST_URL;
                    a.defaultTab = 'preview';
                    a.iframeTitle = 'Vesper preview';
                    a.displayUrl = '/index.html';
                    a.noNav = true;
                    a.noHome = true;
                    a.openInTab = true;
                    art = a;
                  }}
                  expandable
                  style={{ display: 'block', height: '100%' }}
                ></kai-artifact>
              </div>
            </div>
          </kai-resizable-item>
        </kai-resizable>
      </div>
    );
  },
  parameters: {
    docs: {
      source: {
        language: 'html',
        // A representative skeleton of the composition (not the full interactive
        // render). The split is kai-resizable; the right pane is a REAL kai-artifact
        // (Preview/Code toggle, sandboxed preview, file tree, open-in-tab, refresh,
        // maximize). The version dropdown + Inspect + Deploy are labeled gaps —
        // kai-artifact has no toolbar slot to host them.
        code: `<!-- The builder split: chat (left) | preview (right), composed from
     kai-resizable + the chat + kai-artifact. -->
<kai-resizable orientation="horizontal" style="display:block;height:100vh">
  <!-- LEFT: chat thread + composer. min/max give the chat a width floor + ceiling. -->
  <kai-resizable-item size="40%" min="360px" max="480px">
    <header>Vesper editorial
      <kai-tooltip content="Share this build"><kai-button variant="ghost" icon="share">Share</kai-button></kai-tooltip>
    </header>

    <!-- Each assistant generation is a VERSION. kai-artifact has only URL history,
         not a v2/v3 model, so the chip + Restore are hand-wired to navigate(). -->
    <kai-message><!-- content set as a property: the assistant turn --></kai-message>
    <kai-badge>v2</kai-badge>
    <kai-button variant="ghost">Restore this version</kai-button>

    <kai-prompt-input placeholder="Describe a change, or attach a screenshot...">
      <div slot="toolbar-start">
        <kai-menu trigger-icon="plus" label="Add"><!-- Attach image / Import from Figma --></kai-menu>
        <kai-model-switcher></kai-model-switcher>
        <kai-menu trigger-label="Design" trigger-icon-trailing="chevron-down"></kai-menu>
      </div>
    </kai-prompt-input>
  </kai-resizable-item>

  <!-- RIGHT: the preview pane. A REAL kai-artifact with its own toolbar chrome. -->
  <kai-resizable-item>
    <!-- The artifact's OWN toolbar: refresh · expand (maximizes the pane) ·
         open-in-new-tab · address bar · Preview|Code. nav/home hidden via no-*
         flags; the preview is a data: blob, so display-url shows a clean,
         read-only address in the bar instead of leaking the blob. -->
    <kai-artifact src="data:text/html,..." default-tab="preview"
                  no-nav no-home display-url="/index.html" expandable open-in-tab
                  iframe-title="Vesper preview" style="display:block;height:100%"></kai-artifact>
  </kai-resizable-item>
</kai-resizable>

<script type="module">
  // Array/object props are JS properties (the kai- contract); scalars are attributes.
  // The Code tab's file tree + per-file source:
  document.querySelector('kai-artifact').files = [
    { path: 'app/page.tsx', language: 'tsx', code: '…', url: previewUrl },
    { path: 'components/lookbook.tsx', language: 'tsx', code: '…', url: previewUrl }, /* … */
  ];

  // Restore a generation by driving the artifact's own navigate() (the real API).
  const art = document.querySelector('kai-artifact');
  restoreV2Button.addEventListener('kai-click', () => art.navigate(V2_URL));
</script>`,
      },
    },
  },
};
